do CAse CAse &RamoAtividade = 'M' //MERCADO do 'AddMercado' return CAse &RamoAtividade = 'O' // OFICINA do 'AddOficina'
Case &RamoAtividade = 'A' //INDUSTRIA AGRICOLA
otherwise msg('Favor Selecionar um Ramo de Atividade!') &RamoAtividade.SetFocus() EndCAse
